namespace OrdersApi.Models;

/// <summary>Represents the lifecycle status of an order.</summary>
public enum OrderStatus
{
    Pending,
    Processing,
    Shipped,
    Delivered,
    Cancelled
}

using System.ComponentModel.DataAnnotations;
using OrdersApi.Models;

namespace OrdersApi.Models;

/// <summary>Represents an order returned by the API.</summary>
public sealed record OrderResponse(
    int Id,
    int CustomerId,
    DateTimeOffset PlacedAt,
    decimal TotalAmount,
    OrderStatus Status);

/// <summary>Payload for creating a new order.</summary>
public sealed record CreateOrderRequest
{
    /// <summary>The ID of the customer placing the order.</summary>
    [Required]
    public required int CustomerId { get; init; }

    /// <summary>The total monetary amount of the order.</summary>
    [Required]
    [Range(0.01, double.MaxValue, ErrorMessage = "TotalAmount must be greater than zero.")]
    public required decimal TotalAmount { get; init; }
}

namespace OrdersApi.Models;

/// <summary>Represents a customer returned by the API.</summary>
public sealed record CustomerResponse(int Id, string Name);

using OrdersApi.Models;

namespace OrdersApi.Services;

public interface ICustomerService
{
    Task<List<CustomerResponse>> GetAllAsync(CancellationToken cancellationToken = default);
}

using OrdersApi.Models;

namespace OrdersApi.Services;

public sealed class CustomerService : ICustomerService
{
    public Task<List<CustomerResponse>> GetAllAsync(CancellationToken cancellationToken = default)
    {
        return Task.FromResult(new List<CustomerResponse>());
    }
}

using OrdersApi.Models;

namespace OrdersApi.Services;

public interface IOrderService
{
    Task<List<OrderResponse>> GetAllAsync(CancellationToken cancellationToken = default);
    Task<OrderResponse?> GetByIdAsync(int id, CancellationToken cancellationToken = default);
    Task<OrderResponse> CreateAsync(CreateOrderRequest request, CancellationToken cancellationToken = default);
}

using System.Collections.Concurrent;
using OrdersApi.Models;

namespace OrdersApi.Services;

public sealed class OrderService : IOrderService
{
    private readonly ConcurrentDictionary<int, OrderResponse> _orders = new();
    private int _nextId;

    public Task<List<OrderResponse>> GetAllAsync(CancellationToken cancellationToken = default)
    {
        return Task.FromResult(_orders.Values.ToList());
    }

    public Task<OrderResponse?> GetByIdAsync(int id, CancellationToken cancellationToken = default)
    {
        _orders.TryGetValue(id, out var order);
        return Task.FromResult(order);
    }

    public Task<OrderResponse> CreateAsync(CreateOrderRequest request, CancellationToken cancellationToken = default)
    {
        var id = Interlocked.Increment(ref _nextId);
        var order = new OrderResponse(
            id,
            request.CustomerId,
            DateTimeOffset.UtcNow,
            request.TotalAmount,
            OrderStatus.Pending);

        _orders[id] = order;
        return Task.FromResult(order);
    }
}

using Microsoft.AspNetCore.Mvc;
using OrdersApi.Models;
using OrdersApi.Services;

namespace OrdersApi.Controllers;

[ApiController]
[Route("api/[controller]")]
public class CustomersController : ControllerBase
{
    private readonly ICustomerService _service;

    public CustomersController(ICustomerService service)
    {
        _service = service;
    }

    [HttpGet]
    public async Task<ActionResult<List<CustomerResponse>>> GetAll(CancellationToken cancellationToken)
    {
        return Ok(await _service.GetAllAsync(cancellationToken));
    }
}

using Microsoft.AspNetCore.Mvc;
using OrdersApi.Models;
using OrdersApi.Services;

namespace OrdersApi.Controllers;

[ApiController]
[Route("api/[controller]")]
public class OrdersController : ControllerBase
{
    private readonly IOrderService _service;

    public OrdersController(IOrderService service)
    {
        _service = service;
    }

    /// <summary>Returns all orders.</summary>
    [HttpGet]
    public async Task<ActionResult<List<OrderResponse>>> GetAll(CancellationToken cancellationToken)
    {
        return Ok(await _service.GetAllAsync(cancellationToken));
    }

    /// <summary>Creates a new order with status Pending.</summary>
    [HttpPost]
    public async Task<ActionResult<OrderResponse>> Create(
        CreateOrderRequest request, CancellationToken cancellationToken)
    {
        var order = await _service.CreateAsync(request, cancellationToken);
        return CreatedAtAction(nameof(GetById), new { id = order.Id }, order);
    }

    /// <summary>Returns an order by ID.</summary>
    [HttpGet("{id}")]
    public async Task<ActionResult<OrderResponse>> GetById(
        int id, CancellationToken cancellationToken)
    {
        var order = await _service.GetByIdAsync(id, cancellationToken);
        return order is null ? NotFound() : Ok(order);
    }
}

